questions = ["Are the steps in a numbered or ordered list?", "Does it recommend a boiling time between 6 and 8 minutes?", "Does it say to put the egg in cold or ice water after boiling?", "Are the steps in order: boil water, add egg, time it, then cool?", "Does it describe what a medium-boiled egg looks like when done?"]
def _to_bool_answer(item):
  if isinstance(item, bool):
    return item
  if isinstance(item, dict):
    item = item.get('answer', item.get('verdict', ''))
  text = str(item).strip().lower()
  return text in {'yes', 'true', '1', 'pass', 'passed'}

def _parse_content(content_text):
  text = str(content_text or '').strip()
  if not text:
    return None
  if text.startswith('```'):
    text = re.sub(r'^```(?:json)?\s*', '', text)
    text = re.sub(r'\s*```$', '', text)
  parsed = None
  try:
    parsed = json.loads(text)
  except Exception:
    pass
  if parsed is None:
    m = re.search(r'\{[\s\S]*\}', text)
    if m:
      try:
        parsed = json.loads(m.group(0))
      except Exception:
        parsed = None
  if parsed is None:
    m = re.search(r'\[[\s\S]*\]', text)
    if m:
      try:
        parsed = json.loads(m.group(0))
      except Exception:
        parsed = None
  return parsed

def _normalize_answers(parsed, questions):
  if isinstance(parsed, dict):
    if isinstance(parsed.get('answers'), list):
      return {str(i): parsed['answers'][i] for i in range(len(parsed['answers']))}
    numeric_keys = True
    for k in parsed.keys():
      if not str(k).isdigit():
        numeric_keys = False
        break
    if numeric_keys:
      return {str(k): v for k, v in parsed.items()}
    out = {}
    for i, q in enumerate(questions):
      if q in parsed:
        out[str(i)] = parsed[q]
    return out
  if isinstance(parsed, list):
    return {str(i): parsed[i] for i in range(len(parsed))}
  return {}

def ask_batched(out, idx):
  cache_input = out + '\n' + json.dumps(questions, ensure_ascii=False)
  key = hashlib.sha256(cache_input.encode('utf-8')).hexdigest()
  cache = os.path.join(tempfile.gettempdir(), f'promptfoo_batched_v2_{key}.json')
  data = None
  if os.path.exists(cache):
    try:
      with open(cache,'r',encoding='utf-8') as f:
        data = json.load(f)
    except Exception:
      data = None
  if data is None:
    payload = {
      "model": "llama3.1:8b",
      "stream": False,
      "options": {"temperature": 0, "num_gpu": 0, "num_predict": 1024},
      "messages": [
        {"role": "system", "content": "Respond ONLY with JSON: produce a mapping from index to {\"answer\":\"Yes\" or \"No\", \"reason\":\"...\"}. No other text."},
        {"role": "user", "content": f'<o>{out}</o>\n' + '\n'.join(f'{i}: {q}' for i,q in enumerate(questions)) }
      ]
    }
    try:
      p = json.dumps(payload).encode()
      r = urllib.request.urlopen(urllib.request.Request('http://127.0.0.1:11434/api/chat',data=p,headers={'Content-Type':'application/json'}),timeout=300)
    except Exception:
      return False
    try:
      raw = r.read()
      if isinstance(raw, bytes): raw = raw.decode('utf-8', errors='replace')
      resp = json.loads(raw)
      content_text = resp.get('message', {}).get('content', '')
      parsed = _parse_content(content_text)
      data = _normalize_answers(parsed, questions)
    except Exception:
      return False
    try:
      with open(cache,'w',encoding='utf-8') as f:
        json.dump(data,f)
    except Exception:
      pass
  try:
    return _to_bool_answer(data.get(str(idx), ''))
  except Exception:
    return False

return ask_batched(output, 0)

